@startuml
skinparam classAttributeIconSize 0

package "Modulo-matrícula/Informática" {
    [Matrícula] <<C>> #lightgreen;line:green;text:black;bold;;{
        -id: Int
        -cliente: Client
        -tempo: Int
        -quadra: Turma

        +registraMatricula(): Int
    }

    [Aluno] <<C>> #lightblue;line:darkBlue;text:white;italic;;{
        -id: Int
        -nome: String
        -locação: List<Matrícula>


    }


     [Turma] <<C>> #pink;line:red;text:black;underline;;{
         -numero: int 
          -aluguel : Matrícula  
           -ginasio : Curso   

            +getcontroleNúmeroMatricúla() 




}


[Curso]<<c>>#orange;line:brown;text:pink;fontsize=14;;{
-nome:String
-profe
-quadra:list<Turma>



}




interface ControleNúmeromatricula<<I>>   #purple;line:violet;text:white;bolt;;{
       #quantidadeDeMatriula:int

+registaMatricula ():int 

}





' Relações entre classes e interfaces com setas personalizadas para corresponder à imagem original.
'Matricula --> Aluno : composição\n(0..*)\n(composição) \n1
'Turma --|> Matricula : realização
 'Controlematriculas ..> turma : dependência 


end package

@enduml
